module top_module(
  input [31:0] dividend,
  input [31:0] divisor,
  output reg [31:0] remainder
);// Calculate the mod_quotient
  reg [31:0] mod_quotient;
  assign mod_quotient = dividend / divisor;

  // Calculate the product of the mod_quotient and the divisor
  reg [31:0] product;
  assign product = mod_quotient * divisor;

  // Subtract the product from the dividend to get the remainder
  always @(*) begin
    remainder = dividend - product;
  end

endmodule
